from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about an airport (or related entity) into a single fluent sentence.
    The function groups triples by their subject and builds a readable description using simple
    phrase templates for each predicate.
    """
    if not triples:
        return ""

    # Group triples by subject (most cases will have a single subject)
    subjects = {}
    for t in triples:
        subjects.setdefault(t.subject, []).append(t)

    sentences = []
    for subj, rels in subjects.items():
        parts = []
        # Start with the subject itself
        subject_phrase = subj
        # Collect predicate‑object pairs
        for r in rels:
            p, o = r.predicate, r.object
            # Normalise object to string (remove surrounding quotes if present)
            if isinstance(o, str) and o.startswith('"') and o.endswith('"'):
                o = o[1:-1]

            # Map predicates to short textual fragments
            if p == "cityServed":
                parts.append(f"serves the city of {o}")
            elif p == "location":
                parts.append(f"is located in {o}")
            elif p == "country":
                parts.append(f"is in {o}")
            elif p == "elevationAboveTheSeaLevel":
                parts.append(f"is {o} metres above sea level")
            elif p == "elevationAboveTheSeaLevelInFeet":
                parts.append(f"is {o} feet above sea level")
            elif p == "runwayName":
                parts.append(f"has runway {o}")
            elif p == "runwayLength":
                parts.append(f"with a length of {o} metres")
            elif p == "runwayLengthFeet" or p == "1stRunwayLengthFeet":
                parts.append(f"with a length of {o} feet")
            elif p == "runwaySurfaceType" or p.endswith("RunwaySurfaceType"):
                parts.append(f"featuring a {o.lower()} surface")
            elif p == "iataLocationIdentifier":
                parts.append(f"has IATA code {o}")
            elif p == "icaoLocationIdentifier":
                parts.append(f"has ICAO code {o}")
            elif p == "locationIdentifier":
                parts.append(f"has location identifier {o}")
            elif p == "operatingOrganisation":
                parts.append(f"is operated by {o}")
            elif p == "owner":
                parts.append(f"is owned by {o}")
            elif p == "isPartOf":
                parts.append(f"is part of {o}")
            elif p == "regionServed":
                parts.append(f"serves the region of {o}")
            elif p == "hubAirport":
                parts.append(f"uses {o} as a hub airport")
            # Fallback for any other predicate
            else:
                parts.append(f"{p.replace('_', ' ')} {o}")

        # Combine parts into a single sentence
        if parts:
            sentence = f"{subject_phrase} " + ", ".join(parts) + "."
        else:
            sentence = f"{subject_phrase}."
        sentences.append(sentence)

    # Join sentences for multiple subjects
    return " ".join(sentences)

# EVOLVE-BLOCK-END

